## 10. PATTERNS FOR ADDING GOOGLE DRIVE SERVICE

Following the established conventions, here's how to add a Google Drive service:

### 1. Update config model (`internal/config/config.go`):
```go
type Config struct {
    Gmail    bool         `json:"gmail"`
    Calendar CalendarMode `json:"calendar"`
    Contacts bool         `json:"contacts"`
    Drive    bool         `json:"drive"`    // Add this
}

func (c Config) OAuthScopes() []string {
    var scopes []string
    // ... existing ...
    if c.Drive {
        scopes = append(scopes, "https://www.googleapis.com/auth/drive.readonly")
    }
    return scopes
}
```

### 2. Create API wrapper (`internal/google/drive.go`):
```go
package google

import (
    "context"
    "fmt"
    "golang.org/x/oauth2"
    "google.golang.org/api/drive/v3"
    "google.golang.org/api/option"
)

// DriveClient provides read-only access to Google Drive.
// No create, update, or delete operations exist in this type.
type DriveClient struct {
    svc *drive.Service
}

func NewDriveClient(ctx context.Context, ts oauth2.TokenSource) (*DriveClient, error) {
    svc, err := drive.NewService(ctx, option.WithTokenSource(ts))
    if err != nil {
        return nil, fmt.Errorf("creating drive service: %w", err)
    }
    return &DriveClient{svc: svc}, nil
}

func (c *DriveClient) ListFiles(ctx context.Context, pageSize int64) ([]*drive.File, error) {
    resp, err := c.svc.Files.List().
        PageSize(pageSize).
        Fields("files(id,name,mimeType,createdTime,modifiedTime)").
        Context(ctx).
        Do()
    if err != nil {
        return nil, fmt.Errorf("listing files: %w", err)
    }
    return resp.Files, nil
}

func (c *DriveClient) GetFile(ctx context.Context, fileID string) (*drive.File, error) {
    file, err := c.svc.Files.Get(fileID).
        Fields("*").
        Context(ctx).
        Do()
    if err != nil {
        return nil, fmt.Errorf("getting file %s: %w", fileID, err)
    }
    return file, nil
}

func (c *DriveClient) SearchFiles(ctx context.Context, query string, pageSize int64) ([]*drive.File, error) {
    resp, err := c.svc.Files.List().
        Q(query).
        PageSize(pageSize).
        Fields("files(id,name,mimeType)").
        Context(ctx).
        Do()
    if err != nil {
        return nil, fmt.Errorf("searching files: %w", err)
    }
    return resp.Files, nil
}
```

### 3. Create CLI command (`cmd/drive.go`):
```go
package cmd

import (
    "context"
    "github.com/PanthroCorp-Limited/openclaw-skills/google-workspace/internal/config"
    gw "github.com/PanthroCorp-Limited/openclaw-skills/google-workspace/internal/google"
    "github.com/PanthroCorp-Limited/openclaw-skills/google-workspace/internal/oauth"
    "github.com/spf13/cobra"
)

var driveCmd = &cobra.Command{
    Use:   "drive",
    Short: "Read-only Google Drive operations",
}

func driveClient() (*gw.DriveClient, context.Context) {
    ctx := context.Background()
    key := encryptionKey()
    if key == "" {
        exitf("GOOGLE_WORKSPACE_TOKEN_KEY is not set")
    }

    cfg, err := config.Load(configDir)
    if err != nil {
        exitf("loading config: %v", err)
    }
    if !cfg.Drive {
        exitf("drive is disabled in config; run 'google-workspace config set --drive=true'")
    }

    token, err := oauth.LoadToken(configDir, key)
    if err != nil {
        exitf("%v", err)
    }

    oauthCfg := oauth.NewOAuthConfig(clientID(), clientSecret(), cfg.OAuthScopes())
    ts := oauthCfg.TokenSource(ctx, token)

    client, err := gw.NewDriveClient(ctx, ts)
    if err != nil {
        exitf("creating drive client: %v", err)
    }
    return client, ctx
}

var driveListCmd = &cobra.Command{
    Use:   "list",
    Short: "List Drive files",
    Run: func(cmd *cobra.Command, args []string) {
        client, ctx := driveClient()
        files, err := client.ListFiles(ctx, 50)
        if err != nil {
            exitf("%v", err)
        }
        printJSON(files)
    },
}

func init() {
    driveCmd.AddCommand(driveListCmd)
    rootCmd.AddCommand(driveCmd)
}
```

### 4. Update SKILL.md manifest:
```yaml
