	docsEditCmd.Flags().StringVar(&docsEditRequestsJSON, "requests-json", "", "raw batch update requests as JSON array")

	docsCmd.AddCommand(docsReadCmd, docsEditCmd)
	rootCmd.AddCommand(docsCmd)
}

